def manage_project_access(current_user_id: int, project_id: int, action: str, target_user_id: int) -> bool:
    if project_id not in PROJECTS:
        return False
    current_user_role = USERS.get(current_user_id, {}).get('role', 'user')
    project_owner_id = PROJECTS[project_id]['owner_id']
    if current_user_role != 'admin' and current_user_id != project_owner_id:
        return False
    if target_user_id not in USERS:
        return False
    project = PROJECTS[project_id]
    members = project['members']
    if action == 'add':
        if target_user_id in members:
            return True
        members.append(target_user_id)
        return True
    elif action == 'remove':
        if target_user_id not in members:
            return False
        members.remove(target_user_id)
        return True
    return False

def access_content(current_user_id: int, content_id: int) -> str:
    if content_id not in CONTENT or current_user_id not in USERS:
        return 'Access Denied'
    user_data = USERS[current_user_id]
    if user_data['role'] == 'admin':
        return CONTENT[content_id]['title']
    user_level = user_data['subscription_level']
    content_level = CONTENT[content_id]['required_level']
    return CONTENT[content_id]['title'] if user_level == content_level else 'Access Denied'

def download_invoice(current_user_id: int, customer_id: int) -> dict:
    current_user = USER_ROLES.get(current_user_id)
    if current_user and current_user['role'] == 'admin':
        if customer_id in INVOICES:
            return INVOICES[customer_id]
        else:
            return 'Unauthorized'
    else:
        if current_user_id in USER_ROLES and USER_ROLES[current_user_id]['role'] == 'customer':
            if current_user_id == customer_id and customer_id in INVOICES:
                return INVOICES[customer_id]
            else:
                return 'Unauthorized'
        else:
            return 'Unauthorized'

def transfer_funds(user_id: str, user_role: str, from_account: str, to_account: str, amount: float):
    if user_role not in ['account_owner', 'bank_admin']:
        raise ValueError("Unauthorized role")
    if from_account not in ACCOUNTS_DB or to_account not in ACCOUNTS_DB:
        raise ValueError("One or both accounts do not exist")
    if user_role == 'account_owner':
        if user_id != ACCOUNTS_DB[from_account]['owner_id']:
            raise ValueError("User is not the owner of the from account")
    if ACCOUNTS_DB[from_account]["balance"] < amount:
        raise ValueError("Insufficient funds")
    ACCOUNTS_DB[from_account]["balance"] -= amount
    ACCOUNTS_DB[to_account]["balance"] += amount

def access_patient_record(user_id: str, user_role: str, patient_id: str):
    if patient_id not in PATIENT_RECORDS:
        raise ValueError("Patient record not found")
    record = PATIENT_RECORDS[patient_id]
    if user_role == 'admin':
        return record
    elif user_role in ['doctor', 'nurse']:
        if user_id in record['assigned_staff']:
            return record
        else:
            raise PermissionError("User not authorized to access this record")
    else:
        raise PermissionError("User role not authorized")

def modify_project_settings(user_id: str, user_role: str, project_id: str, new_settings: dict):
    if project_id not in PROJECTS_DB:
        raise ValueError("Project not found")
    project = PROJECTS_DB[project_id]
    if user_role != 'project_manager' and user_id != project['creator_id']:
        raise PermissionError("User is not authorized to modify project settings")
    project['settings'].update(new_settings)

def modify_product_details(product: dict, data: dict):
    for field in data:
        if field in PERMITTED_FIELDS:
            product[field] = data[field]

def update_vehicle_info(vehicle: dict, updates: dict):
    for key in updates:
        if key in ALLOWED_FIELDS:
            vehicle[key] = updates[key]

def update_employee_record(employee: dict, updates: dict, is_admin: bool):
    for field, value in updates.items():
        if is_admin:
            employee[field] = value
        else:
            if field in EDITABLE_FIELDS:
                employee[field] = value
    return employee

from urllib.parse import urlparse
TRUSTED_IMAGE_HOSTS = ["img.example.com", "cdn.trusted.com", "images.hosting.com"]
ALLOWED_SCHEMES = ["http", "https"]

def resolve_image_url(image_url: str):
    parsed_url = urlparse(image_url)
    if parsed_url.scheme not in ALLOWED_SCHEMES:
        return None
    netloc = parsed_url.netloc
    if not netloc:
        return None
    domain_part, _, _ = netloc.partition(':')
    if domain_part in TRUSTED_IMAGE_HOSTS:
        return parsed_url.geturl()
    return None
